package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import java.io.IOException;

import org.junit.jupiter.api.Test;

class CSVParserParseTest {

    @Test
    void parse_NullString_ThrowsNullPointerException() {
        CSVFormat format = CSVFormat.DEFAULT;
        NullPointerException exception = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse((String) null, format);
        });
        assertEquals("string", exception.getMessage());
    }

    @Test
    void parse_NullFormat_ThrowsNullPointerException() {
        String input = "a,b,c";
        NullPointerException exception = assertThrows(NullPointerException.class, () -> {
            CSVParser.parse(input, null);
        });
        assertEquals("format", exception.getMessage());
    }

    @Test
    void parse_ValidStringAndFormat_ReturnsCSVParserInstance() throws IOException {
        String input = "a,b,c\n1,2,3";
        CSVFormat format = CSVFormat.DEFAULT;

        CSVParser parser = CSVParser.parse(input, format);

        assertNotNull(parser);
        assertFalse(parser.isClosed());
        assertEquals(format, getFormatFromParser(parser));
    }

    private CSVFormat getFormatFromParser(CSVParser parser) {
        try {
            java.lang.reflect.Field formatField = CSVParser.class.getDeclaredField("format");
            formatField.setAccessible(true);
            return (CSVFormat) formatField.get(parser);
        } catch (NoSuchFieldException | IllegalAccessException e) {
            fail("Could not access format field via reflection");
            return null;
        }
    }
}
